function DonutChart() {
  const segments = [
    { label: "Auto", pct: 50, color: C.farmBlue },
    { label: "Home", pct: 30, color: C.goldLight },
    { label: "Specialty", pct: 12, color: "#2ECC71" },
    { label: "Bristol", pct: 5, color: C.farmRed },
    { label: "Other", pct: 3, color: "#9B59B6" },
  ];
  const r = 38,
    cx = 50,
    cy = 50;
  const circ = 2 * Math.PI * r;
  let cumulative = 0;
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 20 }}>
      <svg width={110} height={110} viewBox="0 0 100 100">
        <circle
          cx={cx}
          cy={cy}
          r={r}
          fill="none"
          stroke={C.midBg}
          strokeWidth="18"
        />
        {segments.map((seg, i) => {
          const dashLen = (seg.pct / 100) * circ;
          const offset = -(cumulative / 100) * circ;
          cumulative += seg.pct;
          return (
            <circle
              key={i}
              cx={cx}
              cy={cy}
              r={r}
              fill="none"
              stroke={seg.color}
              strokeWidth="18"
              strokeDasharray={`${dashLen} ${circ}`}
              strokeDashoffset={offset}
              transform={`rotate(-90 ${cx} ${cy})`}
            />
          );
        })}
        <text
          x="50"
          y="44"
          textAnchor="middle"
          fill="white"
